// src/pages/LiveTracking.jsx
import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, LayerGroup, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import WebSocketService from '../services/WebSocketService';
import api from '../services/api';

// Fix Leaflet default marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

// Fit bounds to include all vehicles
const FitBounds = ({ vehicles }) => {
  const map = useMap();
  useEffect(() => {
    if (vehicles.length > 0) {
      const bounds = L.latLngBounds(vehicles.map(v => [v.lat, v.lng]));
      map.fitBounds(bounds, { padding: [50, 50] });
    }
  }, [vehicles, map]);
  return null;
};

// Colored icon by status
const getIconByStatus = (status) => {
  let colorUrl;
  switch (status) {
    case 'ACTIVE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|00FF00'; // green
      break;
    case 'IDLE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|FFFF00'; // yellow
      break;
    case 'MAINTENANCE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|FF0000'; // red
      break;
    default:
      colorUrl = markerIcon;
  }

  return new L.Icon({
    iconUrl: colorUrl,
    shadowUrl: markerShadow,
    iconSize: [30, 50],
    iconAnchor: [15, 50],
    popupAnchor: [0, -45],
    shadowSize: [41, 41],
  });
};

const LiveTracking = () => {
  const [vehicles, setVehicles] = useState([]);
  const [filter, setFilter] = useState('all');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        const response = await api.get('/vehicles');
        setVehicles(response.data);
      } catch (err) {
        console.error('Error fetching vehicles:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();

    // WebSocket subscription
    WebSocketService.connect(() => {
      WebSocketService.subscribe('/topic/vehicles', (vehicleData) => {
        setVehicles(prev => {
          const filtered = prev.filter(v => v.id !== vehicleData.id);
          return [...filtered, vehicleData];
        });
      });
    });

    return () => WebSocketService.disconnect();
  }, []);

  const filteredVehicles = filter === 'all'
    ? vehicles
    : vehicles.filter(v => v.status === filter);

  return (
    <div className="space-y-6">
      <h2 className="g-title">Live Vehicle Tracking</h2>

      {/* Filter */}
      <div className="flex space-x-4 mb-4">
        <select
          className="g-input"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="all">All Vehicles</option>
          <option value="ACTIVE">Active</option>
          <option value="IDLE">Idle</option>
          <option value="MAINTENANCE">Maintenance</option>
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Map */}
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Map</h3>
          {loading ? (
            <p className="text-gray-600">Loading map...</p>
          ) : (
            <MapContainer
              center={[20.5937, 78.9629]}
              zoom={5}
              className="w-full h-[600px] rounded-lg shadow-md"
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />

              <FitBounds vehicles={filteredVehicles} />

              <LayerGroup>
                {filteredVehicles.map(vehicle => (
                  <Marker
                    key={vehicle.id}
                    position={[vehicle.lat, vehicle.lng]}
                    icon={getIconByStatus(vehicle.status)}
                  >
                    <Popup>
                      🚗 Vehicle {vehicle.id} <br /> Status: {vehicle.status}
                    </Popup>
                  </Marker>
                ))}
              </LayerGroup>
            </MapContainer>
          )}
        </div>

        {/* Vehicle List */}
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle List</h3>
          {filteredVehicles.length === 0 ? (
            <p className="text-gray-600">No vehicles found.</p>
          ) : (
            <div className="overflow-y-auto max-h-[500px]">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-gray-100">
                    <th className="p-2">ID</th>
                    <th className="p-2">Status</th>
                    <th className="p-2">Location</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredVehicles.map(vehicle => (
                    <tr key={vehicle.id} className="border-b">
                      <td className="p-2">{vehicle.id}</td>
                      <td className="p-2">{vehicle.status}</td>
                      <td className="p-2">{`(${vehicle.lat}, ${vehicle.lng})`}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LiveTracking;
